// Combine all RSS feeds into trending topics
const feeds = [
  ...$input.byIndex[0].json.items || [],
  ...$input.byIndex[1].json.items || [],
  ...$input.byIndex[2].json.items || []
];

// Extract top 10 headlines
const headlines = feeds
  .slice(0, 20)
  .map(item => ({
    title: item.title,
    link: item.link,
    pubDate: item.pubDate
  }));

const headlinesText = headlines.map((h, i) => `${i + 1}. ${h.title}`).join('\n');

return {
  json: {
    headlines,
    headlinesText,
    categories: ['Sports', 'Politics', 'Economy', 'Entertainment', 'Technology', 'International'],
    today: new Date().toISOString().split('T')[0]
  }
};

// Parse Gemini response to extract JSON
const geminiResponse = $input.first().json.response;
let topics = [];

try {
  // Try to find JSON array
  const jsonMatch = geminiResponse.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    topics = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON array found');
  }
} catch (e) {
  // Fallback: return empty
  topics = [];
}

// Validate and format topics
const validTopics = topics.filter(t => t.title && t.question && t.category).map((t, i) => ({
  suggested_title: t.title,
  suggested_question: t.question,
  suggested_description: t.description || '',
  suggested_category: t.category,
  ai_reasoning: t.reasoning || '',
  ai_confidence: Math.min(Math.max(t.confidence || 0.7, 0), 1),
  status: 'pending',
  generated_at: new Date().toISOString()
}));

return {
  json: {
    topics: validTopics,
    count: validTopics.length
  }
};

// Format Telegram notification in Bengali
const topics = $input.byIndex[0].json;
const savedTopics = topics || [];

const message = `
🤖 <b>দৈনিক AI টপিক তৈরি হয়েছে</b>

📊 <b>সংখ্যা:</b> ${savedTopics.length}টি টপিক
🏷️ <b>ক্যাটাগরি:</b> ${savedTopics.map(t => t.suggested_category).join(', ')}
⏱️ <b>সময়:</b> ${new Date().toLocaleString('bn-BD')}

${savedTopics.map((t, i) => `${i + 1}. ${t.suggested_title}`).join('\n')}

🔗 <a href="https://polymarket-bangladesh.vercel.app/sys-cmd-7x9k2/daily-topics">টপিক দেখুন</a>
`.trim();

return {
  json: {
    message,
    topics_count: savedTopics.length
  }
};

// Final result
return {
  json: {
    success: true,
    topics_generated: $input.byIndex[0].json.count || 0,
    telegram_sent: true,
    timestamp: new Date().toISOString()
  }
};
